"""
mkt-original commentary — Proverbs 10–12
Run: python3 scripts/zc-original-proverbs-10-12.py

Chs 10–22:16 are the first Solomonic collection, dominated by antithetical couplets
(ṣaddîq/rāšāʿ; ḥākām/kĕsîl). Commentary focuses on Hebrew philology and key translation
choices in the MKT. Key contested terms: ḥesed (10:12; dispute_level=4), ṣĕdāqāh (10:2;
dispute_level=3), tĕšûʿāh (11:14), nepeš as reflexive pronoun (11:17), pĕrî ṣaddîq
ʿēṣ ḥayyîm (11:30), and the ʾōraḥ ṣĕdāqāh ḥayyîm formula (12:28).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

PROVERBS = {
"10": {
"1": "<p><strong>Proverbs of Solomon</strong> (10:1) — a new collection heading; distinguishes this antithetical-couplet corpus from the discourses of chs 1–9. The <em>bēn ḥākām / bēn kĕsîl</em> (wise son / fool son) contrast sets the collection's dominant register: wisdom is relational and has social consequences, beginning in the home.</p>",
"2": "<p><strong>ṣĕdāqāh tassîl mimmāwet</strong> — &#8220;righteousness delivers from death.&#8221; <em>Ṣĕdāqāh</em> (H6666) has a semantic range from judicial rectitude to generosity/almsgiving; in rabbinic Hebrew it narrowed to charity. The MKT renders &#8220;righteousness&#8221; to preserve the forensic and moral range. &#8220;Delivers from death&#8221; (<em>tassîl mimmāwet</em>) is the Proverbs life/death binary: wisdom-aligned conduct leads away from the trajectory of Sheol.</p>",
"3": "<p><strong>lōʾ-yaʿăzōb YHWH nepeš ṣaddîq</strong> — &#8220;the LORD does not let the righteous go hungry.&#8221; Literally, &#8220;YHWH will not let the soul of the righteous go hungry (<em>rāʿāb</em>).&#8221; <em>Nepeš</em> is frequently rendered &#8220;soul&#8221; but here functions as the vitalizing appetite of the whole person. <em>Hāwat rĕšāʿîm</em> (the craving of the wicked) uses <em>hawwāh</em> — desire bordering on greed — which YHWH actively frustrates.</p>",
"4": "<p><strong>rāš ʿōśê kap rĕmiyyāh</strong> — a slack (<em>rĕmiyyāh</em>) hand brings poverty. <em>Rĕmiyyāh</em> can mean both &#8220;slack/lazy&#8221; and &#8220;deceitful/treacherous&#8221; — the same word used of the false balance in 11:1. The pun is live: slackness is a form of deception, pretending to work.</p>",
"5": "<p><strong>ʿōśê māśkîl</strong> — &#8220;a wise son gathers in summer&#8221; (lit. &#8220;acts wisely&#8221;). The agricultural image (<em>qāṣîr</em>, harvest) grounds wisdom in observable seasonal reality — there is a right time for action. <em>Mēbîš</em> (causes shame) is the consistent antonym of wisdom in Proverbs: shame is the social consequence of the fool&#8217;s failure to read time and circumstances.</p>",
"6": "<p><strong>bĕrākôt lĕrōʾš ṣaddîq</strong> — &#8220;blessings crown the head of the righteous.&#8221; <em>Bĕrākāh</em> (blessing) flows naturally to the righteous person; the chiastic second half — &#8220;the mouth of the wicked conceals violence (<em>ḥāmās</em>)&#8221; — contrasts blessings on the head with violence hidden in the mouth. Words both reveal and conceal character.</p>",
"7": "<p><strong>zēker ṣaddîq liḇrākāh</strong> — &#8220;the memory of the righteous is a blessing.&#8221; The verse affirms that moral reputation outlasts life itself: the righteous leave a name that blesses posterity, while the wicked&#8217;s name rots (<em>yirqāb</em>). This is not immortality but <em>šēm</em>-honor — the blessing of being remembered well.</p>",
"8": "<p><strong>ḥakam-lēb yiqqaḥ miṣwôt</strong> — &#8220;the wise in heart (<em>lēb</em>) accepts commands.&#8221; <em>Lēb</em> (heart/mind) is the Proverbs seat of will and understanding together; wisdom is not abstract intelligence but integrated character. <em>Yiqqaḥ miṣwôt</em> (receives commands) contrasts with the babbling fool (<em>ʾĕwîl śĕpātayim</em>) who talks rather than heeds.</p>",
"9": "<p><strong>hôlēk battōm yēlēk beṭaḥ</strong> — &#8220;whoever walks in integrity (<em>tōm</em>) walks securely (<em>beṭaḥ</em>).&#8221; <em>Tōm</em> (integrity/completeness) is used of complete fidelity in covenant contexts. <em>Beṭaḥ</em> (security, trust) is the condition of the one whose path is not crooked; the double-<em>walk</em> (<em>hôlēk... yēlēk</em>) emphasizes that integrity and security travel together.</p>",
"10": "<p><strong>qōrēṣ ʿāyin</strong> — &#8220;the one who winks with malice.&#8221; The eye-wink (<em>qāraṣ ʿayin</em>) signals deceptive intent (cf. 6:13); it communicates what is not said aloud, making the winking person a disruptor of communal trust. The fool who babbles (repeated from v8) disrupts trust differently — with too many words rather than too few.</p>",
"11": "<p><strong>maqqôr ḥayyîm</strong> — &#8220;fountain of life.&#8221; The mouth-as-fountain image is central to Proverbs&#8217; speech theology: the righteous person&#8217;s words are life-giving like a spring. The image recurs at 13:14; 14:27; 16:22 (each time as <em>maqqôr ḥayyîm</em>). The wicked&#8217;s mouth, by contrast, &#8220;conceals violence (<em>ḥāmās</em>)&#8221; — the same word used for pre-flood human wickedness (Gen 6:11).</p>",
"12": "<p><strong>ḥesed tĕkassē kol-pĕšāʿîm</strong> — &#8220;love covers all offenses.&#8221; <em>Ḥesed</em> (H2617; dispute_level=4) is one of the most theologically loaded Hebrew words: covenant loyalty, steadfast love, mercy. The MKT renders &#8220;love&#8221; here to capture both the relational and affective dimensions. The verse is quoted directly in 1 Pet 4:8, applied to fervent love among believers. The covering of offenses is not blind indifference but actively absorbing conflict rather than inflaming it.</p>",
"13": "<p><strong>ḥokmāh... śĕbĕṭ lĕgēw ḥăsar-lēb</strong> — wisdom on the lips of the discerning; a rod for the back of those who lack <em>lēb</em> (heart/understanding). The rod is not punitive cruelty but the corrective consequence designed to produce the understanding the fool refuses to acquire through instruction. Wisdom is the default state of the discerning; corporal correction is the fallback.</p>",
"14": "<p><strong>ḥăkāmîm yiṣpĕnû dāʿat</strong> — &#8220;wise people store up knowledge.&#8221; <em>Ṣāpan</em> (store, hide) — the same verb used for Moses&#8217; mother hiding him (Exod 2:2) — suggests that knowledge is a strategic reserve, not for display. The fool&#8217;s mouth, by contrast, is <em>mĕḥittāh qĕrōbāh</em> (destruction near): voluble ignorance brings harm down quickly.</p>",
"15": "<p><strong>hôn ʿāšîr qiryat ʿuzzô</strong> — &#8220;a wealthy person&#8217;s riches are like a fortified city (<em>qiryat ʿuzzô</em>).&#8221; The verse observes social reality without endorsing it: wealth functions as protection, while poverty is the poor man&#8217;s ruin. The observation is later complicated by v22 (the blessing of YHWH makes truly rich) and 11:4 (wealth is useless on the day of wrath).</p>",
"16": "<p><strong>pĕʿullat ṣaddîq lĕḥayyîm</strong> — &#8220;the earnings of the righteous lead to life (<em>ḥayyîm</em>).&#8221; The ṣaddîq / rāšāʿ binary extends into economics: the righteous person&#8217;s labor produces life, while the wicked&#8217;s income (<em>tĕbûʾat rāšāʿ</em>) leads to sin. The point is not that poverty is sinful but that money is morally directional.</p>",
"17": "<p><strong>ʾōraḥ lĕḥayyîm šômēr mûsār</strong> — &#8220;whoever keeps instruction (<em>mûsār</em>) is on the path of life (<em>ʾōraḥ ḥayyîm</em>).&#8221; <em>Mûsār</em> is disciplinary instruction (from <em>yāsar</em>, to chastise/correct) — formation through correction. The <em>path-of-life</em> formula (also 6:23; Ps 16:11) is a major organizing metaphor of wisdom: life is a road, and attending to correction keeps the traveler on the right one.</p>",
"18": "<p><strong>mĕkassē śinaʾāh śiprê šāqer</strong> — &#8220;whoever conceals hatred has lying lips.&#8221; The verse probes the relationship between speech and inner reality: the person who hides hatred through polished speech is a liar by definition. <em>Śinaʾāh</em> (hatred) beneath smooth words is the precise dynamics of hypocrisy; the second line compounds it with slander (<em>môṣîʾ dibbāh</em> — spreading an evil report).</p>",
"19": "<p><strong>bĕrōb dĕbārîm lōʾ-yĕḥdal pāšaʿ</strong> — &#8220;when words are many, sin is not absent.&#8221; One of Proverbs&#8217; most concise speech-ethics axioms. <em>Ḥōśēk śĕpātāyw maskîl</em> — &#8220;whoever restrains his lips is prudent.&#8221; <em>Ḥāśak</em> (restrain, hold back) is active verbal discipline. The proverb captures a consistent wisdom insight: more words = more opportunity for sin; restraint = wisdom.</p>",
"20": "<p><strong>kesep niḇḥār lĕšôn ṣaddîq</strong> — &#8220;the tongue of the righteous is like choice silver.&#8221; The tongue-as-precious-metal image measures the value of righteous speech: rare, refined, and valuable. The heart of the wicked, by contrast, has <em>kimʿāṭ</em> (little value). The contrast is between refined utterance and worthless interior disposition.</p>",
"21": "<p><strong>śiptê ṣaddîq yirʿû rabbîm</strong> — &#8220;the lips of the righteous feed many.&#8221; <em>Rāʿāh</em> (to feed/shepherd) extends the agricultural/pastoral register: righteous speech is pastoral, sustaining a community. Fools, by contrast, die (<em>yāmûtû</em>) for lack of heart (<em>lēb</em>). The inversion is sharp: the righteous nourish others while fools cannot even sustain themselves.</p>",
"22": "<p><strong>bĕrakat YHWH hîʾ taʿăšîr</strong> — &#8220;the blessing of YHWH is what truly makes rich.&#8221; The adverb <em>hîʾ</em> (it is this that) places the emphasis: not diligence alone, not strategy, but YHWH&#8217;s blessing. <em>Wĕlōʾ-yôsip ʿeṣeb ʿimmāh</em> (he adds no sorrow to it) — the blessing of YHWH comes without the grief that accompanies wealth gained by other means (cf. v15, where riches without YHWH&#8217;s blessing are a fragile fortress).</p>",
"23": "<p><strong>kimśĕḥōq lĕkĕsîl ʿăśôt zimmāh</strong> — &#8220;doing wrong is like a game to a fool.&#8221; <em>Zimmāh</em> (wicked scheme/lewdness) is treated as entertainment (<em>śĕḥōq</em>, laughter) by the fool. The serious moral weight of evil is invisible to those without wisdom. By contrast, wisdom (<em>ḥokmāh</em>) is the <em>śimḥāh</em> (delight) of the person of understanding — their genuine pleasure.</p>",
"24": "<p><strong>megôrat rāšāʿ hîʾ tĕbôʾennû</strong> — &#8220;what the wicked fears will come upon him.&#8221; The self-fulfilling nature of the wicked person&#8217;s trajectory: their <em>megôrāh</em> (dread, the thing dreaded) comes to them. The contrast with the righteous whose longing (<em>taʾăwat ṣaddîqîm</em>) is granted positions desire and dread as directional: you receive what you are oriented toward.</p>",
"25": "<p><strong>kĕʿābōr sûpāh wĕʾên rāšāʿ wĕṣaddîq yĕsôd ʿôlam</strong> — &#8220;when the storm passes, the wicked are gone; the righteous stand on an everlasting foundation (<em>yĕsôd ʿôlam</em>).&#8221; The storm metaphor is eschatological in Proverbs: ultimate stability belongs to the righteous because their foundation is ʿôlam (eternal/lasting). The wicked have no such anchor; they are swept away.</p>",
"26": "<p><strong>kĕḥōmeṣ lĕšinnayim ûkĕʿāšān lĕʿênāyim</strong> — &#8220;like vinegar to the teeth and smoke to the eyes.&#8221; The uncomfortable sensory images (acid on teeth, irritating smoke) capture the frustration of relying on a lazy person. The proverb uses physical discomfort as the experiential equivalent of the social cost of laziness.</p>",
"27": "<p><strong>yirʾat YHWH tôsîp yāmîm</strong> — &#8220;the fear of YHWH (<em>yirʾat YHWH</em>) adds length to life.&#8221; The fear-of-YHWH formula is Proverbs&#8217; epistemological anchor (1:7; 9:10); here it has a directly temporal consequence: added days. The wicked&#8217;s years are <em>yiqṣōrû</em> (cut short) — the life/death binary expressed in longevity terms.</p>",
"28": "<p><strong>tôḥelet ṣaddîqîm śimḥāh</strong> — &#8220;the hope of the righteous brings joy.&#8221; <em>Tôḥelet</em> (hope, expectation) in Proverbs is not wishful thinking but confident anticipation rooted in YHWH&#8217;s ordering of the world. The wicked&#8217;s expectation (<em>tiqwat rĕšāʿîm</em>) comes to nothing (<em>tōʾbad</em>) — not because hope is wrong but because their hope is misplaced.</p>",
"29": "<p><strong>māʿôz lattōm derek YHWH</strong> — &#8220;the LORD&#8217;s way (<em>derek YHWH</em>) is a stronghold (<em>māʿôz</em>) for the blameless.&#8221; The divine way — YHWH&#8217;s path of governance — is simultaneously shelter for those who walk it and ruin (<em>mĕḥittāh</em>) for those who work evil. The same divine order that protects the righteous destroys the wicked.</p>",
"30": "<p><strong>ṣaddîq lĕʿôlam bal-yimmôṭ</strong> — &#8220;the righteous will never be dislodged (<em>yimmôṭ</em>).&#8221; <em>Mōṭ</em> (to totter, slip, be dislodged) is used of the unstable; the righteous have secure footing (<em>lĕʿôlam</em>, forever). The wicked will not inhabit the land (<em>ereṣ</em>) — reversing the covenant promise; evil disrupts the conditions of the covenantal land.</p>",
"31": "<p><strong>pî ṣaddîq yānûb ḥokmāh</strong> — &#8220;the mouth of the righteous produces wisdom.&#8221; <em>Nûb</em> (to bear fruit) is an agricultural verb applied to speech — the mouth of the righteous is a fruit-bearing plant. The perverse tongue (<em>tahpûkôt</em>) will be cut off (<em>tikārēt</em>). The speech-plant metaphor that ends ch10 anticipates 11:30&#8217;s &#8220;fruit of the righteous is a tree of life.&#8221;</p>",
"32": "<p><strong>śiptê ṣaddîq yēdĕʿûn rāṣôn</strong> — &#8220;the lips of the righteous know what is pleasing (<em>rāṣôn</em>).&#8221; <em>Rāṣôn</em> (pleasure, favor, delight) implies social and theological attunement: the righteous person&#8217;s speech is pleasing to YHWH and to people because it is rightly calibrated. The wicked&#8217;s mouth speaks only <em>tahpûkôt</em> (perversities, turnings-upside-down).</p>"
},
"11": {
"1": "<p><strong>môʾznê mirmāh tôʿăbat YHWH</strong> — &#8220;dishonest scales are detestable (<em>tôʿăbāh</em>) to YHWH.&#8221; <em>Môʾznê mirmāh</em> (deceitful balances) is a marketplace-ethics formula recurring across the ANE; the OT uniquely grounds market honesty in YHWH&#8217;s character rather than social convention (cf. Lev 19:36; Deut 25:13-15; Mic 6:11). <em>ʾeben šĕlēmāh</em> (accurate/complete weight, lit. &#8220;whole stone&#8221;) — completeness (<em>šālēm</em>) in measurement reflects divine wholeness.</p>",
"2": "<p><strong>bāʾ zādôn wayyābōʾ qālôn</strong> — &#8220;when pride (<em>zādôn</em>) arrives, disgrace follows.&#8221; <em>Zādôn</em> (presumptuous pride, arrogance) is the pride of a person who oversteps their creaturely limits. <em>Ṣānûʿîm ḥokmāh</em> (with the humble is wisdom) — <em>ṣānûaʿ</em> (humble, modest) occurs only here and Mic 6:8 (&#8220;walk humbly with your God&#8221;). Wisdom accompanies this specific form of lowliness — not servile but rightly measured.</p>",
"3": "<p><strong>tummâ yĕšārîm tanḥēm</strong> — &#8220;the integrity (<em>tummāh</em>) of the upright guides them.&#8221; <em>Tummāh</em> (completeness, wholeness, integrity) is the noun form of <em>tōm</em> (10:9); it functions as an internal guide — the integrated person is self-directing in the right path. The treacherous (<em>bōgedîm</em>) are destroyed by their own treachery&#8217;s perversion of their path.</p>",
"4": "<p><strong>lōʾ-yôʿîl hôn bĕyôm ʿebrāh</strong> — &#8220;wealth is of no use on the day of wrath (<em>yôm ʿebrāh</em>).&#8221; <em>Yôm ʿebrāh</em> (day of wrath/overflow) appears in Zeph 1:15-18 as the eschatological day of judgment; Proverbs uses the phrase for the moment when divine governance reasserts itself decisively against accumulated wickedness. On that day, <em>ṣĕdāqāh</em> (righteousness) alone delivers from death — echoing 10:2.</p>",
"5": "<p><strong>ṣidqat tāmîm tĕyaššēr darkô</strong> — &#8220;the righteousness of the blameless (<em>tāmîm</em>) makes his way straight (<em>tĕyaššēr</em>).&#8221; <em>Tāmîm</em> (blameless, complete, whole) is the cultic-moral ideal for the person in covenant with YHWH (Gen 17:1; Job 1:1). The straight path is not self-achieved but is the consequence of integrated righteousness; the wicked fall by their own wickedness — a self-undoing.</p>",
"6": "<p><strong>ṣidqat yĕšārîm taṣṣîlēm</strong> — the righteousness of the upright rescues them. The verse parallels 10:2 with <em>taṣṣîlēm</em> (rescues them) where the object is plural — righteousness is communal rescue as well as individual. The treacherous are caught by their own evil desire (<em>ḥawwat</em> — the same greedy-craving from 10:3), trapped by what they reached for.</p>",
"7": "<p><strong>bĕmôt ʾādām rāšāʿ tōʾbad tiqwāh</strong> — &#8220;when a wicked man dies, his expectation (<em>tiqwāh</em>) perishes.&#8221; <em>Tiqwāh</em> (hope, a thing hoped for; lit. the string of hope) dissolves at death for the wicked because their hope was grounded in the present order. <em>Wĕtôḥelet ʾônim ʾābādāh</em> (the hope of wrongdoers comes to nothing) — both the wicked&#8217;s expectation and the results they counted on evaporate.</p>",
"8": "<p><strong>ṣaddîq miṣṣārāh neḥĕlāṣ</strong> — &#8220;the righteous are rescued (<em>neḥĕlāṣ</em>) from trouble.&#8221; <em>Ḥālaṣ</em> (to draw out, rescue) is a rescue vocabulary word used of divine deliverance. The wicked take the righteous&#8217;s place in the trouble — a substitutionary exchange in reverse of what is expected; the moral order eventually redirects suffering toward its true source.</p>",
"9": "<p><strong>bĕpeh ḥānēp yašḥit rēʿēhû</strong> — &#8220;through his words the godless person (<em>ḥānēp</em>) destroys his neighbor.&#8221; <em>Ḥānēp</em> (godless, profane, one who has corrupted their relation to the sacred) is a stronger term than mere wickedness — it implies deliberate sacrilege. Their speech is destructive; the righteous are saved <em>bĕdaʿat</em> (through knowledge/discernment) — knowledge as shield.</p>",
"10": "<p><strong>bĕṭûb ṣaddîqîm taʿălōz qiryāh</strong> — &#8220;when the righteous prosper, the city (<em>qiryāh</em>) rejoices.&#8221; The proverb locates moral character within communal space: the righteous person&#8217;s wellbeing (<em>ṭûb</em>) is civic property that generates urban joy. This is the social-capital dimension of wisdom: the righteous bless the city, the wicked degrade it.</p>",
"11": "<p><strong>bĕbirkat yĕšārîm tārûm qāret</strong> — &#8220;by the blessing of the upright the city is lifted up (<em>tārûm</em>).&#8221; <em>Rûm</em> (to be exalted, lifted up) in this civic context suggests moral elevation — the city rises through the quality of its people&#8217;s speech and character. The wicked&#8217;s mouth tears it down — the city&#8217;s fate is determined by its speech environment.</p>",
"12": "<p><strong>bāz lĕrēʿēhû ḥăsar-lēb</strong> — &#8220;whoever despises his neighbor lacks good sense (<em>ḥăsar-lēb</em>).&#8221; <em>Bāzāh</em> (to despise, treat as worthless) applied to a neighbor is the mark of heart-deficiency. <em>ʾîš tĕbûnôt yaḥărîš</em> (a person of understanding stays silent) — restraint is the mark of tĕbûnāh (discernment); silence in the face of a neighbor&#8217;s faults is more sophisticated than contempt.</p>",
"13": "<p><strong>hôlēk rākîl mĕgalleh-sôd</strong> — &#8220;whoever goes about gossiping (<em>rākîl</em>) reveals secrets.&#8221; <em>Rākîl</em> (a slanderer/gossip) is from a root meaning &#8220;to go about as a trader&#8221; — the gossip traffics in secrets as a merchant traffics in goods. <em>Neʾĕman-rûaḥ</em> (faithful of spirit) keeps confidence (<em>mĕkassēh sôd</em>) — covers/hides the secret rather than trading in it.</p>",
"14": "<p><strong>bĕʾên taḥbûlôt yippol ʿām</strong> — &#8220;without guidance (<em>taḥbûlôt</em>), a people falls.&#8221; <em>Taḥbûlôt</em> (pl. of taḥbûlāh) is the nautical term for the ropes used to steer a ship — plural because effective governance requires multiple steering mechanisms. <em>Tĕšûʿāh</em> (safety/deliverance — from the root <em>yāšaʿ</em>, same as <em>yĕšûʿāh</em>/salvation) comes with many counselors.</p>",
"15": "<p><strong>rāʿ yērōaʿ kî ʿārab zār</strong> — &#8220;whoever gives surety for a stranger will suffer harm.&#8221; The surety-for-a-stranger warning recurs in Proverbs (6:1-5; 17:18; 20:16; 22:26-27) — financial entanglement with unknown parties is consistently presented as a wisdom failure, not just financial risk. <em>Śōnēʾ tĕqîʿôt bōṭēaḥ</em> (whoever refuses such pledges is safe) — the safe path is refusal of the obligation.</p>",
"16": "<p><strong>ʾēšet ḥēn titmlĕk kābôd</strong> — &#8220;a gracious (<em>ḥēn</em>) woman gains honor.&#8221; <em>Ḥēn</em> is unearned favor; the gracious woman attracts honor (<em>kābôd</em>) through her relational quality rather than force. Ruthless men (<em>ʿārîṣîm</em>) gain only wealth (<em>ʿōšer</em>) — the contrast of honor versus money tracks a deeper wisdom distinction between what is intrinsically valuable and what is merely economically useful.</p>",
"17": "<p><strong>gōmēl napšô ʾîš ḥāsed</strong> — &#8220;a kind man benefits himself (<em>napšô</em>).&#8221; <em>Nepeš</em> here functions reflexively (himself, his own person) rather than as soul or appetite. <em>Ḥāsed</em> (lovingkindness) enacted toward others returns on the practitioner. The cruel person (<em>ʾakzārî</em>) disturbs his own flesh (<em>šĕʾērô</em>) — his cruelty circles back to harm him at a visceral level.</p>",
"18": "<p><strong>rāšāʿ ʿōśē pĕʿullat šeqer</strong> — &#8220;the wicked earns deceptive wages.&#8221; <em>Šeqer</em> (falsehood, deceptiveness) as a modifier for wages: what the wicked earns is inherently unreliable. By contrast, <em>zōrēaʿ ṣĕdāqāh śekar ʾĕmet</em> — &#8220;whoever sows righteousness gains a sure (<em>ʾĕmet</em>) reward.&#8221; <em>Śekar ʾĕmet</em> (wage of truth/reliability) — the harvest metaphor for moral consequence.</p>",
"19": "<p><strong>kēn ṣĕdāqāh lĕḥayyîm</strong> — &#8220;genuine righteousness leads to life.&#8221; The adverb <em>kēn</em> (so, truly, genuinely) stresses the authentic quality of the righteousness that produces life — not performance but substance. <em>Ûmĕradef rāʿāh lĕmôtô</em> — &#8220;whoever pursues evil runs toward his own death.&#8221; The active pursuit (<em>rādap</em>, to chase/hunt) of evil is self-directed death-seeking.</p>",
"20": "<p><strong>tôʿăbat YHWH ʿiqqĕšê-lēb</strong> — &#8220;those with crooked hearts (<em>ʿiqqĕšê-lēb</em>) are detestable to YHWH.&#8221; <em>ʿIqqēš</em> (crooked, twisted, perverse) denotes structural distortion of the <em>lēb</em> (heart/will). YHWH&#8217;s delight (<em>rĕṣônô</em>) is in those whose way (<em>derek</em>) is blameless (<em>tĕmîmê-derek</em>) — the perfect path arising from an integrated character.</p>",
"21": "<p><strong>yād lĕyād lōʾ-yinnāqeh rāʿ</strong> — &#8220;hand to hand, the wicked will not go unpunished.&#8221; The phrase <em>yād lĕyād</em> (hand to hand) may describe conspiring (joining hands to plot evil) or simply emphasizes certainty (you can count on it). <em>Wĕzera ṣaddîqîm nimlāṭ</em> (the offspring of the righteous will escape) — the righteous person&#8217;s moral legacy extends to their children.</p>",
"22": "<p><strong>nēzem zāhāb bĕʾap ḥăzîr</strong> — &#8220;like a gold ring in a pig&#8217;s snout.&#8221; The deliberately jarring image — expensive jewelry in an unclean animal — captures the waste of beauty without discretion (<em>ṭaʿam</em>, taste/judgment). Physical beauty (<em>yāpāh</em>) is valuable but misplaced without the wisdom to use it well. The proverb is not misogynistic but is making a point about the relationship between surface qualities and character.</p>",
"23": "<p><strong>taʾăwat ṣaddîqîm ʾak-ṭôb</strong> — &#8220;the desire (<em>taʾăwāh</em>) of the righteous ends in good (<em>ṭôb</em>).&#8221; The righteous person&#8217;s desires are themselves righteous — the integration of character means that what they want is what is good. The wicked&#8217;s hope (<em>tiqwat rĕšāʿîm</em>) brings wrath — the word <em>ʿebrāh</em> (wrath/overflow) connects to 11:4&#8217;s day of wrath.</p>",
"24": "<p><strong>yēš mĕpazzēr wĕnôsāp ʿôd</strong> — &#8220;one person gives freely and grows richer.&#8221; One of Proverbs&#8217; most counter-intuitive economic observations: liberality (<em>pāzar</em>, scatter/disperse) increases, while withholding (<em>ḥāśak</em> from the proper amount) leads to want. The paradox of generous economics reflects a wisdom understanding of <em>bĕrākāh</em> (blessing) as replenishing rather than depleting.</p>",
"25": "<p><strong>nepeš bĕrākāh tĕduššān</strong> — &#8220;a generous person (<em>nepeš bĕrākāh</em>, a soul of blessing) will be enriched.&#8221; The phrase <em>nepeš bĕrākāh</em> (soul/person of blessing) is unusual — the person has become so identified with generosity that blessing is their very nature. <em>Ûmarweh gam-hûʾ yôreh</em> — &#8220;whoever waters others will himself be watered.&#8221; The agricultural metaphor of irrigation applied to social generosity.</p>",
"26": "<p><strong>mônēaʿ bār yiqbûhû lĕʾôm</strong> — &#8220;the people curse whoever hoards grain.&#8221; <em>Qābab</em> (to curse) reflects the social contract around food distribution in an agrarian community: grain-hoarding during scarcity violates communal covenant and brings collective cursing. <em>Bĕrākāh lĕrōʾš maśbîr</em> (blessings on the head of the one who sells) — generosity in the market is a communal blessing.</p>",
"27": "<p><strong>šōḥēr ṭôb yĕbaqqēš rāṣôn</strong> — &#8220;whoever earnestly seeks good (<em>ṭôb</em>) will gain favor (<em>rāṣôn</em>).&#8221; <em>Šāḥar</em> (to seek eagerly, seek at dawn — same root as <em>šaḥar</em>, dawn) implies an early and earnest seeking. Seeking <em>rāʿāh</em> (evil) brings the same evil on the seeker — the moral reciprocity principle that structures chs 10-12.</p>",
"28": "<p><strong>bôṭēaḥ bĕʿošrô hûʾ yippōl</strong> — &#8220;whoever trusts (<em>bāṭaḥ</em>) in his wealth will fall.&#8221; <em>Bāṭaḥ</em> (to trust, rely on) is the key covenantal-trust verb usually directed toward YHWH (Ps 22:5; 37:3); trusting in wealth redirects it from YHWH to mammon. <em>Kĕʿāleh yipraḥ ṣaddîqîm</em> (the righteous will flourish like a green leaf/branch) — <em>ʿāleh</em> (fresh leaf) suggests vibrant, life-connected growth.</p>",
"29": "<p><strong>ʿōkēr bêtô yinḥal rûaḥ</strong> — &#8220;whoever brings trouble on his own household will inherit the wind.&#8221; <em>ʿākar</em> (to trouble, disturb — used of Achan in Josh 7:25-26) and <em>rûaḥ</em> (wind, breath) — nothing to show, nothing to hold. <em>Wĕʿebed ḥākām liḇnê-bôšet</em> (the fool ends up serving the wise) — the social reversal: the household-destroyer becomes a servant.</p>",
"30": "<p><strong>pĕrî-ṣaddîq ʿēṣ ḥayyîm</strong> — &#8220;the fruit of the righteous is a tree of life (<em>ʿēṣ ḥayyîm</em>).&#8221; The <em>ʿēṣ ḥayyîm</em> (tree of life) links back to Gen 2-3 and forward to Rev 22:2; Proverbs uses it in 3:18 (wisdom is a tree of life) and 15:4 (a healing tongue). Here the righteous person&#8217;s <em>pĕrî</em> (fruit, produce — their deeds and influence) is itself life-giving to others. <em>Lōqēaḥ nĕpāšôt ḥākām</em> (the wise wins souls) — <em>lāqaḥ</em> as capture/take; winning people to wisdom.</p>",
"31": "<p><strong>hēn ṣaddîq bāʾāreṣ yĕšullām</strong> — &#8220;if the righteous receive their due on earth (<em>bāʾāreṣ</em>).&#8221; The <em>qal wāḥōmer</em> (light-to-heavy argument): if even the righteous receive consequences on earth, how much more the wicked and the sinner. The verse does not say the righteous deserve punishment but that the earthly order renders judgment on all; the wicked&#8217;s reckoning is therefore assured.</p>"
},
"12": {
"1": "<p><strong>ʾōhēb mûsār ʾōhēb dāʿat</strong> — &#8220;whoever loves discipline (<em>mûsār</em>) loves knowledge (<em>dāʿat</em>).&#8221; The love of <em>mûsār</em> (corrective instruction) is the pragmatic test of whether someone genuinely wants knowledge. <em>Śōnēʾ tôkaḥat baʿar</em> (whoever hates correction is without understanding — lit. &#8220;is stupid/brutish&#8221;) — <em>baʿar</em> (H1197, brutish, like a dumb animal) is the strongest negative term in Proverbs&#8217; vocabulary for intellectual deficiency.</p>",
"2": "<p><strong>ṭôb yāpîq rāṣôn mēʾet YHWH</strong> — &#8220;a good man obtains favor (<em>rāṣôn</em>) from YHWH.&#8221; <em>Pûq rāṣôn</em> (to bring forth favor) — <em>pûq</em> is to bring out a supply, suggesting favor is available and the good person draws on it. <em>Wĕʾîš mĕzimmôt yarśîaʿ</em> (a man who schemes wickedly he condemns) — YHWH&#8217;s condemnation is the decisive reversal of the schemer&#8217;s plans.</p>",
"3": "<p><strong>lōʾ-yikkôn ʾādām bĕrešaʿ</strong> — &#8220;no one is made secure by wickedness.&#8221; <em>Kûn</em> (to be established, secured, firm) in the niphal is the word for a stable foundation; wickedness cannot produce it. <em>Wĕšōreš ṣaddîqîm bal-yimmôṭ</em> (the root of the righteous will not be shaken) — the root (<em>šōreš</em>) image is organic and deep; the righteous person is grounded where wickedness cannot go.</p>",
"4": "<p><strong>ʾēšet ḥayil ʿăteret baʿlāh</strong> — &#8220;an excellent wife (<em>ʾēšet ḥayil</em>) is a crown to her husband.&#8221; <em>Ḥayil</em> (valor, strength, ability) in <em>ʾēšet ḥayil</em> is the same phrase used for the Woman of Valor in 31:10 — the ideal of full competence and character. <em>Ûkĕrāqāb bĕʿaṣmôtāyw</em> (shame is like decay in his bones) — the contrast of crown-honor and bone-rot is deliberately visceral.</p>",
"5": "<p><strong>maḥšĕbôt ṣaddîqîm mišpāṭ</strong> — &#8220;the plans of the righteous are just (<em>mišpāṭ</em>).&#8221; <em>Maḥšābet</em> (plan, thought) as the interior level of moral action: the righteous person&#8217;s thinking itself is justice-shaped. The schemes (<em>taḥbûlôt</em>) of the wicked are deceitful (<em>mirmāh</em>) — the same word used for dishonest scales in 11:1.</p>",
"6": "<p><strong>diḇrê rĕšāʿîm ʾĕrob-dām</strong> — &#8220;the words of the wicked set an ambush for blood (<em>ʾĕrob-dām</em>).&#8221; The wicked person&#8217;s speech is predatory — an ambush laid with words. <em>Pî yĕšārîm yaṣṣîlēm</em> (the mouth of the upright delivers people) — the same mouth-as-agent that ambushes in the wicked rescues in the upright.</p>",
"7": "<p><strong>hāpok rĕšāʿîm wĕʾênām</strong> — &#8220;the wicked are overthrown and are gone.&#8221; <em>Hāpak</em> (to overturn, be overthrown) is the verb of Sodom&#8217;s destruction (Gen 19:29; Isa 13:19) — the wicked person&#8217;s end is a catastrophic overturning with no recovery. <em>Bêt ṣaddîqîm yaʿămōd</em> (the house of the righteous stands firm) — the household as the durable unit of righteous life.</p>",
"8": "<p><strong>lĕpî-śiklô yĕhullal ʾîš</strong> — &#8220;a man is praised according to his wisdom (<em>śekel</em>).&#8221; <em>Śekel</em> (prudence, good sense) is the practical-intelligence dimension of wisdom. <em>Naʿăwē-lēb</em> (twisted of mind/heart) is the antonym — structural deformation of the <em>lēb</em> that produces contempt (<em>bāzāh</em>) from others. Reputation tracks inner character.</p>",
"9": "<p><strong>ṭôb niqləh wĕʿebed lô</strong> — &#8220;it is better to be of humble standing and have a servant than to put on airs (<em>mitkabbēd</em>) and lack bread.&#8221; The proverb punctures pretension: self-aggrandizement (<em>kābad</em> in the hitpael — presenting oneself as honored) that is materially empty is worse than genuine but modest sufficiency. Reality outranks performance.</p>",
"10": "<p><strong>yôdēaʿ ṣaddîq nepeš bĕhemtô</strong> — &#8220;a righteous man cares for the wellbeing (<em>nepeš</em>) of his animal.&#8221; <em>Nepeš</em> applied to the animal — the righteous person attends to the animal&#8217;s vitality and appetite. <em>Wĕraḥămê rĕšāʿîm ʾakzārî</em> (even the compassion of the wicked is cruel) — the wicked person&#8217;s apparent mercy contains cruelty; character shapes every act.</p>",
"11": "<p><strong>ʿōbēd ʾadmātô yiśbaʿ lāḥem</strong> — &#8220;whoever works his land will have plenty of bread.&#8221; The agricultural work-ethic proverb: tilling the land (<em>ʿābad ʾadāmāh</em>) produces bread (<em>śābaʿ lāḥem</em>). <em>Mĕraḥēp rêqîm ḥăsar-lēb</em> (whoever chases empty pursuits lacks heart/sense) — <em>rêqîm</em> (empty things, vain pursuits) is the pursuit of what cannot sustain.</p>",
"12": "<p><strong>ḥāmad rāšāʿ mĕṣôd rāʿîm</strong> — &#8220;the wicked craves what evil people catch.&#8221; <em>Ḥāmad</em> (to desire covetously — used in the Decalogue, Exod 20:17) applied to the wicked person&#8217;s desire for the prey of other evil people — coveting even the fruits of evil. <em>Šōreš ṣaddîqîm yittēn</em> (the root of the righteous produces its own fruit) — the righteous person generates their own fruitfulness, not dependent on predatory acquisition.</p>",
"13": "<p><strong>bĕpeša śĕpātayim môqēš rāʿ</strong> — &#8220;an evil man is trapped (<em>môqēš</em>, a snare) by the sins of his lips.&#8221; Speech as self-entrapment: the evil person&#8217;s own words form the snare. <em>Wĕyēṣē miṣṣārāh ṣaddîq</em> (the righteous escapes from trouble) — the juxtaposition of the wicked trapped by speech and the righteous escaping trouble highlights the moral asymmetry in crisis.</p>",
"14": "<p><strong>miprî pî-ʾîš yiśbaʿ-ṭôb</strong> — &#8220;from the fruit of his words a man is satisfied with good.&#8221; The mouth-as-fruit-tree image of 11:30 extended to the satisfaction (<em>śābaʿ</em>) of the speaker himself. <em>Ûpĕʿullat yĕdê ʾādām tāšûb lô</em> (the work of his hands comes back to him) — the reciprocity principle: both verbal and manual labor return their quality to the agent.</p>",
"15": "<p><strong>derek ʾĕwîl yāšār bĕʿênāyw</strong> — &#8220;the path of a fool seems right (<em>yāšār</em>) in his own eyes.&#8221; Self-perception as epistemological trap: the fool&#8217;s path is subjectively right because he lacks the external correction that exposes its error. <em>Wĕšômēaʿ lāʿēṣāh ḥākām</em> (a wise person listens to counsel) — receptivity to external correction is the distinguishing mark of wisdom over folly.</p>",
"16": "<p><strong>ʾĕwîl bayyôm yiwwādaʿ kaʿasô</strong> — &#8220;a fool&#8217;s annoyance (<em>kaʿas</em>) is known at once.&#8221; <em>Kaʿas</em> (vexation, anger, irritation) is immediately public when it belongs to the fool — no filter between inner state and outer expression. <em>Wĕkōsē qālôn ʿārûm</em> (a prudent person overlooks an insult) — <em>kāsāh</em> (to cover) is the same verb used of love covering offenses in 10:12; the prudent person applies the same covering to minor social slights.</p>",
"17": "<p><strong>yāpîaḥ ʾĕmûnāh yaggîd ṣedeq</strong> — &#8220;a truthful witness (<em>ʿēd ʾĕmet</em>) gives honest testimony (<em>ṣedeq</em>).&#8221; <em>ʾĂmûnāh</em> (faithfulness, reliability) is the character quality behind truthful testimony; the true witness&#8217;s words are <em>ṣedeq</em> (right, just). <em>Wĕʿēd šĕqārîm mirmāh</em> (a false witness deceitfulness) — the false witness&#8217;s core is <em>mirmāh</em> (treachery, the dishonest-scales word of 11:1).</p>",
"18": "<p><strong>yēš bôṭē dōbĕr kĕmadqĕrôt ḥāreb</strong> — &#8220;reckless words (<em>bôṭē</em>) pierce like sword-thrusts (<em>madqĕrôt ḥāreb</em>).&#8221; <em>Bāṭāh</em> (to speak rashly/thoughtlessly) creates word-weapons: the image of being stabbed by speech captures the visceral damage of careless talk. <em>Wĕlāšôn ḥăkāmîm marpēʾ</em> (the tongue of the wise brings healing — <em>marpēʾ</em>) — the same tongue-instrument that pierces in the reckless heals in the wise.</p>",
"19": "<p><strong>śĕpat ʾĕmet tikkôn lāʿad</strong> — &#8220;truthful lips stand firm (<em>tikkôn</em>) forever (<em>lāʿad</em>).&#8221; <em>Kûn</em> in the niphal (to be established, firm) applied to truthful lips: truth has ontological staying power — it is established in the order of things. <em>Wĕʿad-ʾargeʿāh lĕšôn šāqer</em> (a lying tongue lasts only a moment) — <em>ʾargeʿāh</em> (a moment, a wink of time) is the lifespan of the lie.</p>",
"20": "<p><strong>mirmāh bĕlēb ḥōrĕšê rāʿ</strong> — &#8220;deceit fills the heart of those who plan evil.&#8221; <em>Ḥāraš</em> (to plow, to devise) — the agricultural metaphor of plowing applied to devising evil; the heart-field is plowed with deceit. <em>Wĕliôʿăṣê šālôm śimḥāh</em> (those who counsel peace find joy) — <em>šālôm</em> as the goal of speech acts and its reward being <em>śimḥāh</em> (genuine joy).</p>",
"21": "<p><strong>lōʾ-yĕʾunneh laṣṣaddîq kol-ʾāwen</strong> — &#8220;no harm (<em>ʾāwen</em>) happens to the righteous.&#8221; <em>ʾĀwen</em> (trouble, wickedness, iniquity) in the sense of harm that befalls one. The proverb is experiential wisdom, not a metaphysical guarantee; its counterpart is that the wicked are filled with trouble (<em>rāʿāh</em>). The righteous person&#8217;s moral alignment creates a form of protection.</p>",
"22": "<p><strong>tôʿăbat YHWH śiprê šāqer</strong> — &#8220;lying lips are detestable (<em>tôʿăbāh</em>) to YHWH.&#8221; The <em>tôʿăbāh</em>-formula (applied to dishonest scales in 11:1; to lying lips here) marks the most serious moral violations — those that are not merely unwise but abhorrent to divine character. <em>Wĕʿōśê ʾĕmûnāh rĕṣônô</em> (those who act faithfully are his delight) — <em>ʾĕmûnāh</em> as faithful reliability is the positive pole of YHWH&#8217;s pleasure.</p>",
"23": "<p><strong>ʾādām ʿārûm kōsē dāʿat</strong> — &#8220;a prudent man (<em>ʿārûm</em>) conceals what he knows.&#8221; <em>ʿĀrûm</em> (shrewd, prudent) in Proverbs is consistently positive (unlike Gen 3:1 where the serpent is <em>ʿārûm</em> as cunning); the positive <em>ʿārûm</em> conceals knowledge strategically — not deception but disciplined restraint. <em>Wĕlēb kĕsîlîm yiqrāʾ ʾiwwelet</em> (the heart of a fool broadcasts its folly) — folly calls out, wisdom is silent.</p>",
"24": "<p><strong>yad ḥārûṣîm timšôl</strong> — &#8220;the diligent (<em>ḥārûṣ</em>, lit. sharp/incised, hence eager) hand will rule.&#8221; Diligence leads to authority; the lazy (<em>rĕmiyyāh</em>) will be put to forced labor (<em>mas</em>) — the reversal of the expected social position. <em>Mas</em> is tribute-labor, typically imposed on the conquered; the lazy person&#8217;s fate is the lowest social tier.</p>",
"25": "<p><strong>dĕʾāgāh bĕlēb-ʾîš yašḥennāh</strong> — &#8220;anxiety (<em>dĕʾāgāh</em>) in a man&#8217;s heart weighs him down.&#8221; <em>Dĕʾāgāh</em> (anxious care, sorrow) bends (<em>šāḥāh</em>) the heart; the remedy is a <em>ṭôb-dābār</em> (a good word) — a spoken encouragement that makes glad (<em>yĕśamĕḥennāh</em>). The proverb captures the therapeutic power of speech as direct pastoral medicine.</p>",
"26": "<p><strong>yātēr mērēʿēhû ṣaddîq</strong> — &#8220;the righteous man guides his neighbor well.&#8221; <em>Yātēr</em> (to lead, guide) from <em>tûr</em> (to explore, search out a path) — the righteous person scouts the path for others. <em>Wĕderek rĕšāʿîm taṭʿēm</em> (the way of the wicked leads them astray) — <em>tāʿāh</em> (to wander, go astray) as the destination of the wicked person&#8217;s path: leading followers into error.</p>",
"27": "<p><strong>lōʾ-yaḥărōk rĕmiyyāh ṣêdô</strong> — &#8220;the lazy man does not even bother to prepare his game.&#8221; <em>Ḥārak</em> (to roast/singe) — the lazy person captures prey but does not bother to cook it: slackness at every stage, not only in the initial effort. <em>Wĕhôn-ʾādām yāqār ḥārûṣ</em> (the wealth of a diligent man is a precious thing) — diligence makes ordinary wealth precious.</p>",
"28": "<p><strong>bĕʾōraḥ ṣĕdāqāh ḥayyîm</strong> — &#8220;in the path of righteousness is life.&#8221; The climactic statement of ch12 and a summary of the two-ways theme across chs 10-12: righteousness, wisdom, and the path of life are the same road. <em>Wĕderek nĕtîbāh ʾal-māwet</em> — &#8220;and along that road there is no death.&#8221; <em>ʾAl-māwet</em> (no-death) is the fullest expression of the life promised to the wise; the road of righteousness is defined by the absence of the death-trajectory.</p>"
}
}

def main():
    c = load_comm('mkt-original', 'proverbs')
    merge_comm(c, PROVERBS)
    save_comm('mkt-original', 'proverbs', c)
    total = sum(len(vs) for vs in PROVERBS.values())
    print(f'proverbs mkt-original: {total} entries written (ch10-12)')

if __name__ == '__main__':
    main()
